// Only enrich the subject's OWN profile, and only with explicit enrichment consent.
const input = $json;
if (!input.consent || input.consent.enrichment !== true) {
  throw new Error('Enrichment requires explicit consent (consent.enrichment = true).');
}
if (!input.subject_ref || !input.verification_id) {
  throw new Error('Enrichment requires a prior consented self-verification (subject_ref, verification_id).');
}
return [{ json: { ...input, mode: $env.IDENTITY_MODE === 'live' ? 'live' : 'mock' } }];

// Synthetic enrichment for the configured test subject ONLY. Any other subject
// gets empty sources, so the demo cannot enrich real people.
const now = new Date().toISOString().replace(/\.\d{3}Z$/, 'Z');
const input = $('Enrichment consent gate').item.json;
const isTest = input.documento_numero === '30123456';
const sources = isTest ? [
  { source_id: 'afip-padron', name: 'AFIP — Constancia de inscripción (CUIL/CUIT)', category: 'fiscal',
    url: 'https://www.afip.gob.ar/', status: 'mock', mode: 'mock', last_success_at: now, last_error: null,
    records: [ { label: 'Condición', value: 'Monotributo', detail: 'Categoría B' },
               { label: 'Estado', value: 'Activo' } ] },
  { source_id: 'padron-electoral', name: 'Padrón electoral (lugar de votación)', category: 'electoral',
    url: 'https://www.padron.gob.ar/', status: 'mock', mode: 'mock', last_success_at: now, last_error: null,
    records: [ { label: 'Establecimiento', value: 'Escuela N° 123 «Demo»', detail: 'Rosario' },
               { label: 'Mesa', value: '4567' } ] },
  { source_id: 'rdam-santafe', name: 'Registro de Deudores Alimentarios Morosos (Santa Fe)', category: 'registro',
    url: null, status: 'ok_empty', mode: 'mock', last_success_at: now, last_error: null, records: [] },
] : [];
return [{ json: { enrichment: { consented: true, sources }, subject_ref: input.subject_ref,
  verification_id: input.verification_id, mode: input.mode } }];
